INSERT INTO TB_SLA_IGNORE_DATE (
	TB_SLA_IGNORE_DATEID
	, IGNORE_DATE
	, USE_YN
	, REMARK
	, REG_USER_ID
	, REG_DT
) VALUES 
	
	(
	 	NEXTVAL FOR TB_SLA_IGNORE_DATEIDSEQ
		, REPLACE(#{data.IGNORE_DATE}, '/', '')
		, #{data.USE_YN}
		, #{data.REMARK}
		, #{data.REG_USER_ID}
		, CURRENT TIMESTAMP
	)

